INSERT INTO `emailtemplates` (`id`, `email_title`, `email_subject`, `email_content`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Fast Quote Email', 'Fast Quote Email', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {fullname},</b><br />\r\n	<br />\r\n	Thanks for getting started with {company_name}!<br />\r\n	<br />\r\n	We have received request of quote with the information given below.<br />\r\n	<br />\r\n	Package Type:&emsp;&emsp;&emsp; {packagetype}<br />\r\n	Travel Month:&emsp;&emsp;&emsp;&emsp;{travelmonth}<br />\r\n	How many nights: &emsp;&nbsp; &nbsp;{nightsinfo} Nights<br />\r\n	No. of Passengers: &emsp; {passginfo}<br />\r\n	Full Name: &emsp;&emsp;&emsp;&emsp;&emsp;{fullname}<br />\r\n	Phone No.: &emsp;&emsp;&emsp;&emsp;&emsp;{phoneno}<br />\r\n	Email: &nbsp; &nbsp; &nbsp; &nbsp; &emsp;&emsp;&emsp;&emsp;&emsp;{peremail}<br />\r\n	<br />\r\n	<br />\r\n	<b>Best Regards:</b><br />\r\n	{company_name}<br />\r\n	{company_phone}<br />\r\n	{company_email}<br />\r\n	{company_webaddress}</span></p>', 1, '2024-10-15 10:18:58', '2025-03-05 08:57:30'),
(2, 'Enquiry Request', 'Enquiry Request', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {company_name},</b></span><br />\r\n	&nbsp;</p>\r\n<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\">A New&nbsp;<strong>&quot;Enquiry Request&quot;</strong>&nbsp;has received with the information given below.<br />\r\n	<br />\r\n	Full Name: &emsp;&emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp; {estimate_fullname}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Phone No.: &emsp;&emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp; {estimate_phoneno}<br />\r\n	Enquiry Message: &emsp;&emsp;&nbsp; &nbsp; {estimate_msg}</span><br />\r\n	Interested In: &emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; {estimate_packagetype}</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>', 1, '2025-03-05 11:32:04', '2025-04-08 10:37:38'),
(3, 'Beat My Price', 'Beat My Price', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {company_name},</b></span><br />\r\n	&nbsp;</p>\r\n<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\">A New&nbsp;<strong>&quot;Beat My Price&quot;</strong>&nbsp;has received with the following information:<br />\r\n	<br />\r\n	Departure&nbsp; From:&emsp;&emsp;&emsp;&nbsp; {departurefrom}<br />\r\n	Destination City:&emsp;&emsp;&emsp;&emsp;{destinationcity}<br />\r\n	Travel Date: &emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; {travel_date}<br />\r\n	Person Name: &emsp;&emsp;&emsp;&emsp;&nbsp; {personname}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Phone No.: &emsp;&emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp;{phoneno}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Email: &emsp;&emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;{txtemail}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Makkah Nights: &emsp;&emsp;&emsp;&nbsp; &nbsp;{makkahnights}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Madinah Nights: &emsp;&emsp;&emsp;&nbsp; {madinahnights}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Rooms: &emsp;&emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;{rooms}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Accomodation: &emsp;&emsp;&emsp;&nbsp; &nbsp; {accommodation}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Adults: &emsp;&emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;{adults}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Child: &emsp;&emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;{child}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Infants: &emsp;&emsp;&emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; {infants}</span></p>\r\n<p>\r\n	&nbsp;</p>', 1, '2025-03-06 04:40:02', '2025-03-06 04:40:02'),
(4, 'Register For Hajj Packages', 'Register For Hajj Packages', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {company_name},</b></span><br />\r\n	&nbsp;</p>\r\n<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\">A New&nbsp;<strong>&quot;Registeration for Hajj Packages Request&quot;</strong>&nbsp;has received with the information given below.<br />\r\n	<br />\r\n	Name: &emsp;&emsp;&nbsp; &nbsp;{personname}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Email: &emsp;&nbsp; &nbsp; &nbsp; &nbsp;{personemail}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Phone No.:&nbsp; &nbsp; {phoneno}</span></p>\r\n<p>\r\n	&nbsp;</p>', 1, '2025-03-07 06:38:00', '2025-03-07 06:40:04'),
(5, 'Contact Us Request', 'Contact Us Request', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {company_name},</b></span><br />\r\n	&nbsp;</p>\r\n<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\">A New&nbsp;<strong>&quot;Contact Us Request&quot;</strong>&nbsp;has received with the information given below.<br />\r\n	<br />\r\n	Name: &emsp;&emsp;&nbsp; &nbsp;{contact_fullname}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Email: &emsp;&nbsp; &nbsp; &nbsp; &nbsp;{contact_email}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Phone No.:&nbsp; &nbsp; {contact_phoneno}</span><br />\r\n	<span style=\"font-family: arial, helvetica, sans-serif;\">Message:&nbsp; &nbsp; &nbsp; &nbsp;{contact_message}</span></p>\r\n<p>\r\n	&nbsp;</p>', 1, '2025-03-07 09:41:19', '2025-03-07 09:41:19'),
(6, 'Book Now', 'Booking Request', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {frmbooknow_fname},</b><br />\r\n	<br />\r\n	Thanks for getting started with {company_name}!<br />\r\n	<br />\r\n	We have received your booking request with the information given below.<br />\r\n	<br />\r\n	Full Name: &emsp;&emsp;&emsp;&emsp;&emsp;{frmbooknow_fname}<br />\r\n	Phone No.: &emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp;{frmbooknow_contactno}<br />\r\n	Email: &nbsp; &nbsp; &nbsp; &nbsp; &emsp;&emsp;&emsp;&emsp;&emsp;{frmbooknow_email}<br />\r\n	Travel Month:&emsp;&emsp;&emsp;&emsp;{frmbooknow_travel_month}<br />\r\n	No. of Guests: &emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;{frmbooknow_guests}<br />\r\n	Total Days: &emsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; {frmbooknow_total_days} Days<br />\r\n	<br />\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Package Information:</b></span><br />\r\n	Package Name: &emsp;&nbsp;&nbsp;{frmbooknow_package_name} - &pound; {frmbooknow_package_price}<br />\r\n	<br />\r\n	<b>Best Regards:</b><br />\r\n	{company_name}<br />\r\n	{company_phone}<br />\r\n	{company_email}<br />\r\n	{company_webaddress}</span></p>', 1, '2025-05-23 19:18:42', '2025-05-23 19:18:42'),
(7, 'Did not get What you are looking for?', 'Did not get What you are looking for?', '<p>\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><b>Hi {customform_fname},</b><br />\r\n	<br />\r\n	We have received your request with the information given below.<br />\r\n	<br />\r\n	Full Name: &emsp;&emsp;&emsp;&emsp;&emsp;{customform_fname}<br />\r\n	Phone No.: &emsp;&emsp;&emsp;&emsp;&nbsp; &nbsp;{customform_contactno}<br />\r\n	<br />\r\n	<b>Best Regards:</b><br />\r\n	{company_name}<br />\r\n	{company_phone}<br />\r\n	{company_email}<br />\r\n	{company_webaddress}</span></p>', 1, '2025-05-29 10:11:53', '2025-05-29 10:11:53');
