INSERT INTO `hotelinfos` (`hotelinfos_id`, `hotelinfos_name`, `hotelinfos_city`, `hotelinfos_details`, `hotelinfos_status`, `hotelinfos_sort`, `hotelinfos_image`, `created_at`, `updated_at`, `hotelinfos_startype`) VALUES
(3, 'Al Kiswah Towers Hotel', 'Makkah', '<p>\r\n	Al Kiswah Towers Hotel can conveniently provide information at the reception to help guests to get around the area. Arafat is 24 km&nbsp; from the accommodation. King Abdulaziz Airport is 98 km away.</p>', 1, 1, '1741783457-hotel-.webp', '2025-03-12 07:44:17', '2025-03-12 07:44:17', 3),
(5, 'Time Ruba Hotel & Suites', 'Makkah', '<p>\r\n	Located in Makkah, 8.4 km from Hira Cave, TIME Ruba Hotel &amp; Suites provides accommodation with a fitness centre, free private parking, a terrace and a restaurant.</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	With free WiFi, this 4-star hotel offers room service and a 24-hour front desk. Guests can use the indoor pool, or enjoy city views.</p>\r\n<p>\r\n	All guest rooms in the hotel are fitted with a kettle. Complete with a private bathroom equipped with a shower and a hairdryer, all units at TIME Ruba Hotel &amp; Suites have a flat-screen TV and air conditioning, and some rooms here will provide you with a seating area.</p>\r\n<p>\r\n	The units include a safety deposit box.</p>\r\n<p>\r\n	A buffet, continental or vegetarian breakfast is available at the property. Masjid Al Haram is 12 km from the accommodation, while Makkah Museum is 6.3 km away.&nbsp;</p>\r\n<p>\r\n	King Abdulaziz International Airport is 91 km from the property.</p>', 1, 3, NULL, '2025-03-12 15:38:33', '2025-03-12 15:38:33', 5),
(6, 'M Hotel Al Dana Makkah By Millennium', 'Makkah', '<p>\r\n	M Hotel Al Dana Makkah is gracefully situated in Makkah Al Mukarramah, 3.2 km from Masjid Al-Haram. This is a family-friendly hotel with 611 designed rooms</p>', 1, 4, NULL, '2025-03-12 15:40:56', '2025-03-12 15:40:56', 4),
(7, 'Emaar Al Khlil', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Emaar Al Khalil in Makkah offers a convenient location with Masjid Al Haram a 13-minute walk away. Zamzam Well is less than 1 km from the hotel, while King Abdulaziz International Airport is 92 km distant.</span></p>', 1, 5, NULL, '2025-03-12 15:47:56', '2025-03-12 15:48:20', 3),
(8, 'M Hotel Makkah By Millennium', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The M Hotel Makkah by Millennium is a five stars hotel located in the holy city of Makkah Al Mukarramah. Situated on Ibrahim Al Khalil street, just few minutes&#39; drive to holy mosque, 60 and 25 minutes to the rites of pilgrimage. Guests can enjoy free WiFi throughout the property.</span></p>', 1, 6, NULL, '2025-03-12 15:50:30', '2025-03-12 15:50:30', 5),
(9, 'Elaf Bakkah Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Just a 3-minute drive from Al Masjid Al Haram, Elaf Bakkah Hotel is located in Aziziah Mahbas Al Jin. It offers a restaurant with a 24-hour room service. The shopping centres in Aziziah are 5 minutes by car.</span></p>', 1, 7, NULL, '2025-03-12 15:51:45', '2025-03-12 15:51:45', 4),
(10, 'Dar Al-eiman Al Khalil', 'Makkah', '<p>\r\n	<span style=\"color: rgb(0, 0, 0); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px;\">Strategically situated in Ajyad, allowing you access and proximity to local attractions and sights. This 3-star property features restaurant to make your stay more indulgent and memorable.</span></p>', 1, 8, NULL, '2025-03-12 15:54:15', '2025-03-12 15:54:15', 3),
(11, 'Novotel Makkah Thakher City', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Rooms feature air-conditioning, private bathrooms, mountain or city views, and modern amenities such as minibars and work desks. </span><br />\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The family-friendly restaurant offers Indian cuisine with halal options in a modern setting. Breakfast includes continental, American, buffet, vegetarian, and halal selections.</span></p>', 1, 9, NULL, '2025-03-12 15:56:09', '2025-03-12 15:56:09', 4),
(12, 'Saif Al Majd Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Saif Al Majd Hotel in Makkah offers family rooms with air-conditioning, private bathrooms, and free WiFi. Each room includes a TV, work desk, and free toiletries. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Guests benefit from private check-in and check-out, a lift, 24-hour front desk, concierge service, and free on-site parking. Additional amenities include a coffee shop and full-day security.</span></p>', 1, 10, NULL, '2025-03-12 15:57:46', '2025-03-12 15:57:46', 3),
(13, 'Voco Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in Makkah, 1.3 km from Masjid-Al-Haram, voco Makkah an IHG Hotel provides accommodation with a restaurant, private parking is available against charge, and a shared lounge. The accommodation offers a 24-hour front desk, a free shuttle service, room service and free WiFi throughout the property.</span></p>', 1, 11, NULL, '2025-03-12 15:59:33', '2025-03-12 15:59:33', 4),
(14, 'Al Ebaa Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Al Ebaa Hotel in Makkah offers adults-only rooms with air-conditioning, private bathrooms, and modern amenities. Each room includes a work desk, TV, and free toiletries. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests can enjoy a family-friendly restaurant serving halal Middle Eastern and international cuisines. The restaurant offers a continental buffet breakfast and dinner in a welcoming ambience.</span></p>', 1, 12, NULL, '2025-03-12 16:00:51', '2025-03-12 16:00:51', 4),
(15, 'Elaf Ajyad Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in the capital of Islam which has special situation enshrined into all Muslims hearts. A 2 star hotel with spacious rooms, suites, and apartments providing a variety of accommodation types to meet all requirements, including elegantly furnished VIP suites. The Holy Haram is a 350 metres away. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 13, NULL, '2025-03-12 16:04:20', '2025-03-12 16:04:20', 4),
(16, 'Anjum Hotel Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in Mecca, Anjum Hotel Makkah offers modern accomodations with views of the Masjid Al Haram. Free WiFi access is available throughout the entire property. Each unit here will provide you with a flat-screen TV, air conditioning and a mini fridge. Bathrooms are fitted with a shower, a hairdryer and free toiletries. Guests can enjoy local and international menu options at the restaurant or in the room. Room service is available 24 hours.</span></p>', 1, 14, NULL, '2025-03-12 16:05:48', '2025-03-12 16:05:48', 5),
(17, 'Sheraton Makkah Jabal Al Kaaba', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Sheraton Makkah Jabal Al Kaaba Hotel is located in Makkah, within 1 km from Abraj Al Bait and just 570 m from Masjid al-Haram, both accessible through its 60 m private pedestrian bridge. The property is also 22 km away from Um AlQura University and offers free WiFi. The property features two restaurants and Hira Cave is 11 km away. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 15, NULL, '2025-03-12 16:06:53', '2025-03-12 16:06:53', 5),
(18, 'Shaza Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(51, 51, 51); font-family: &quot;Trip Sans VF&quot;, &quot;Trip Sans&quot;, Arial, sans-serif; font-size: 16px;\">Shaza Makkah is located in Jabal Ka&rsquo;aba, a new development close to the Holy Mosque and only a short walk from the city center. The hotel has splendid front views of Al Masjid Al Haram. Shaza Makkah offers 251 beautiful guestrooms and suites. All rooms feature free WiFi, a flat screen television, in-room safe, rain shower, signature toiletries, hairdryer, 24-hour room service, tea and coffee set and laundry service.&nbsp;</span></p>', 1, 16, NULL, '2025-03-12 16:08:32', '2025-03-12 16:08:32', 5),
(19, 'Pullman Zamzam Makkah Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Pullman ZamZam Makkah is located just a few meters away from the Holy Mosque and offers luxurious studios and suites. It features a restaurant and views of the city and the Kaaba. Masjid Al Haram is 100 metres away. Guests can enjoy free WiFi in all areas of the hotel. All the units at Zamzam are air-conditioned and elegantly decorated. They include a seating area with satellite TV and work desk. They also have a mini fridge and a safety deposit box. Some rooms feature Haram/Kaaba views. Guests can enjoy a buffet breakfast or choose to be served in the privacy of their rooms.</span></p>', 1, 17, NULL, '2025-03-12 16:09:37', '2025-03-12 16:09:37', 5),
(20, 'Elaf Kinda Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The 5-star Elaf Kinda Hotel is adjacent to King Abdul Aziz&#39;s waqf facing the al Masjed al haram between King Abdul Aziz Gate and King Fahd Gate, just steps away from the Kaaba and a direct access to the al Masjed al haram. It offers stylish rooms with free WiFi and a flat-screen TV with satellite channels. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 18, NULL, '2025-03-12 16:10:39', '2025-03-12 16:10:39', 5),
(21, 'Riyadh Al Diyafah Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Riyadh Al Deafah Hotel in Makkah offers family rooms with air-conditioning, private bathrooms, and free WiFi throughout the property. Each room includes a tea and coffee maker, refrigerator, seating area, free toiletries, shower, TV, and wardrobe.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests can enjoy a restaurant on-site and benefit from room service. The hotel features a lift, 24-hour front desk, and family rooms, ensuring a pleasant stay. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 19, NULL, '2025-03-12 16:12:26', '2025-03-12 16:12:26', 3),
(22, 'Emaar Andalusia Hotel Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Emaar Andalusia in Makkah offers a convenient location with Masjid Al Haram a 13-minute walk away, Zamzam Well less than 1 km, and King Abdulaziz International Airport 93 km distant.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Rooms feature air-conditioning, private bathrooms, tea and coffee makers, work desks, showers, carpeted floors, TVs, soundproofing, electric kettles, and wardrobes.</span></p>', 1, 20, NULL, '2025-03-12 16:13:30', '2025-03-12 16:13:30', 3),
(23, 'Hotel Barakah Mawaddah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Al Barakah Mawaddah Hotel in Makkah offers family rooms with air-conditioning, private bathrooms, bidets, hairdryers, free toiletries, showers, carpeted floors, TVs, and wardrobes.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests enjoy free WiFi throughout the property, a 24-hour front desk, room service, and multilingual reception staff speaking Arabic and English.</span></p>', 1, 21, NULL, '2025-03-12 16:14:44', '2025-03-12 16:14:44', 3),
(24, 'Dar Al Bayan Hotel', 'Makkah', '<p style=\"margin: 0px 0px 20px; padding: 0px; color: rgb(68, 68, 68); font-family: Raleway, sans-serif; font-size: 14px; background-color: rgb(250, 250, 249);\">\r\n	Featuring Wi-Fi in public areas, the 2-star&nbsp;<strong style=\"margin: 0px; padding: 0px;\">Dar Al Bayan Hotel</strong>&nbsp;Mecca is approximately 10 minutes&#39; drive from the massive Masjid al-Haram Mosque.Welcoming guests to an adjoining terrace and a dressing area, the rooms are furnished with a work desk. They come with a roll-in shower, a tub, and a separate toilet along with such comforts as bath sheets and slippers.Smash Burger is adjacent to this Mecca hotel, a 19-minute walk away.</p>', 1, 22, NULL, '2025-03-12 16:16:01', '2025-03-12 16:16:01', 3),
(25, 'Al Nosour Al Mohajreen Hotel', 'Makkah', '<p style=\"margin: 0px 0px 20px; padding: 0px; color: rgb(68, 68, 68); font-family: Raleway, sans-serif; font-size: 14px; background-color: rgb(250, 250, 249);\">\r\n	<strong style=\"margin: 0px; padding: 0px;\">Al Nosour Al Mohajreen Hotel</strong>&nbsp;Mecca includes 147 rooms and is about a 25-minute walk from Safa and Marwa Holy Mountains. This hotel also features Wi-Fi in public areas.Some rooms open onto the city.</p>', 1, 23, NULL, '2025-03-12 16:17:59', '2025-03-12 16:17:59', 3),
(26, 'Nada Al Deaafah Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Nada Al Diyafah Hotel is located in the Ajyad al sud district in Makkah,behind le Meriedien Hotel and only 150 metres from Masjid Al Haram. Each room at this hotel is air conditioned and comes with a flat-screen TV. You will find a kettle in the room. Rooms include a private bathroom. Nada Al Diyafah Hotel offers complimentary WiFi. There is a 24-hour front desk at the property. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 24, NULL, '2025-03-12 16:18:53', '2025-03-12 16:18:53', 3),
(27, 'Anwar Al Diyafah Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in Makakh, Anwar Al Diyafah offers simply furnished accommodations. Al Masjid Al Haram is a 5-minute walk away. Free WiFi is available throughout the property. Each room here will provide you with a flat-screen TV, air conditioning and a living area. There is a full a kitchenette with a refrigerator and stovetop. The private bathroom also comes with free toiletries. At Anwar Al Diyafah Hotel you will find a 24-hour front desk. Other facilities offered at the property include luggage storage.</span></p>', 1, 25, NULL, '2025-03-12 16:19:46', '2025-03-12 16:19:46', 3),
(28, 'Hotel Barakah Mawaddah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Al Barakah Mawaddah Hotel in Makkah offers family rooms with air-conditioning, private bathrooms, bidets, hairdryers, free toiletries, showers, carpeted floors, TVs, and wardrobes.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests enjoy free WiFi throughout the property, a 24-hour front desk, room service, and multilingual reception staff speaking Arabic and English.</span></p>', 1, 26, NULL, '2025-03-12 16:20:55', '2025-03-12 16:20:55', 3),
(29, 'Hilton Suites Jabal Omar Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Overlooking the Holy Haram, Hilton Suite Makkah is situated in the heart of the city of Makkah. The hotel is only minutes&rsquo; walk from the Grand Mosque and close to the new King Abdullah wing of Haram and Al Shubaikah Umrah entrance Gate. The hotel provides free Wi-Fi and has a private separate Mosque for gents &amp; ladies on the hotel premises.</span></p>', 1, 27, NULL, '2025-03-12 16:25:18', '2025-03-12 16:25:18', 4),
(30, 'Doubletree By Hilton Makkah Jabal Omar', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Doubletree By Hilton Jabal Omar Makkah in Makkah offers spacious rooms with air-conditioning, free WiFi, and modern amenities. Each room includes a work desk, minibar, and TV, ensuring a pleasant stay. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The family-friendly restaurant serves international cuisine with a buffet breakfast and halal options. Guests can enjoy lunch and dinner in a modern ambience, making mealtimes enjoyable.</span></p>', 1, 28, NULL, '2025-03-12 16:27:17', '2025-03-12 16:27:17', 4),
(31, 'Saja Hotels Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Saja Makkah Hotel in Makkah offers family rooms with air-conditioning, private bathrooms, and mountain or city views. Each room includes a tea and coffee maker, bidet, and free WiFi throughout the property. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Guests benefit from a shuttle service, lift, 24-hour front desk, full-day security, and luggage storage. Free on-site private parking is available, along with a work desk and seating area. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 29, NULL, '2025-03-12 16:29:26', '2025-03-12 16:29:26', 4),
(32, 'Al Shohada Hotel By Palm Rich', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Within walking distance of the Holy Al Masjid Al Haram, Al Shohada by Palm Rich Makkah offers luxurious rooms with LCD TVs and air conditioning. Facilities include a business centre. All rooms of Al Shohada by Palm Rich Makkah are equipped with satellite TV and a well-lit work desk. Every room also has a private marble bathroom. Male guests can enjoy a personalised foot massage from an international masseur.</span></p>', 1, 30, NULL, '2025-03-12 16:32:35', '2025-03-12 16:32:35', 5),
(33, 'Makkah Towers', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The 5-star Makkah Towers is overlooking the Makkah&rsquo;s Holy Haram Mosque and the Kaaba. It offers stylish rooms, 7 dining options and a 10,000 seat carpeted prayer hall. Makkah Towers spacious, air-conditioned rooms feature Art Deco-style decor, satellite TV. Kitchenette facilities include a coffee maker, and room service is available throughout the day. . Jasmin Caffe specialises in Arabic coffee and fresh-baked pastries. Chinese and Arabic restaurants are also on site.</span></p>', 1, 31, NULL, '2025-03-12 16:33:36', '2025-03-12 16:33:36', 5),
(34, 'Movenpick Hotel & Residences Hajar Tower Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in one of the tallest buildings in the world and overlooking the holy Grand Mosque, Hajar Tower combines traditions with modern comforts. It features in-house shops and fine dining options. Offering free WiFi, rooms at M&ouml;venpick Hotel &amp; Residence Hajar Tower Makkah are decorated with contemporary wooden furnishings, most facing the Masjid al-Haram and the sacred K&rsquo;aba. All rooms are equipped with a flat-screen satellite TV, tea/coffee making facilities and a minibar. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 32, NULL, '2025-03-12 16:34:38', '2025-03-12 16:34:38', 5),
(35, 'Hilton Makkah Convention Hotel', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Hilton Makkah Convention Hotel, only moments from the Haram, offers majestic views and is close to the Sacred Mosque and few steps from Al Shubaikah Umrah entrance Gate. Our location is convenient to exploring the Holy City of Makkah. This hotel features 3 restaurants, a fitness center and a 24-hour business center. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 33, NULL, '2025-03-12 16:36:37', '2025-03-12 16:36:37', 5),
(36, 'Swissotel Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">As part of the prestigious Abraj Al Bait complex, the deluxe Swissotel Makkah is a contemporary five-star hotel located only 100 metres from the holy Masjid Al Haraam, overlooking the Ka&rsquo;aba, as well as the entire Masjid. All accommodations at Swiss&ocirc;tel have carpeted floors. Each suite offers a spacious seating area with a flat-screen TV and a minibar. A marble bathroom is also included. The restaurant offers fine dining with a selection of mouth-watering seasonal specialties, while at Caf&eacute; Swiss a combination of international and traditional cuisine is served. Room service is available 24 hours. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 34, NULL, '2025-03-12 16:37:39', '2025-03-12 16:37:39', 5),
(37, 'Address Jabal Omar Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Address Jabal Omar Makkah in Makkah offers a convenient location with stunning mountain views. Masjid Al Haram is a 14-minute walk away, while Zamzam Well lies 1 km from the property. King Abdulaziz International Airport is 92 km distant. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Guests enjoy a fitness centre, restaurant, and free WiFi throughout the aparthotel. Additional amenities include a lounge, public bath, fitness room, and 24-hour front desk.</span></p>', 1, 35, NULL, '2025-03-12 16:39:08', '2025-03-12 16:39:08', 5),
(38, 'Jumeirah Jabal Omar Makkah', 'Makkah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Featuring 5-star accommodation, Jabal Omar Jumeirah, Makkah is located in Makkah, 250 m from Masjid Al Haram and 10 km from Hira Cave. Featuring a fitness centre, the 5-star hotel has air-conditioned rooms with free WiFi, each with a private bathroom. The hotel features family rooms. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 36, NULL, '2025-03-12 16:41:17', '2025-03-12 16:41:17', 5),
(39, 'Hotel Tulip Inn Al Daar Rawafid', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Tulip Inn Al Dar Rawafed offers rooms with free WiFi in Al Madinah. The property is less than 10 meter walk from Al-Masjid an-Nabawi , 2.5 km from Mazaya Mall and 3.2 km from Al Baqia Cemetry. The property is 1.1 km from the city Central Madinah. At the hotel, each room comes with a desk, a flat screen TV and a private bathroom. Guest rooms have a wardrobe and coffee tray.</span></p>', 1, 37, NULL, '2025-03-12 16:54:02', '2025-03-12 16:54:02', 3),
(40, 'New Madinah Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The New Madinah Hotel is conveniently located south of the Holy Mosque, just a few minutes from the Al Rawda Al Sharifa and Al Baqie areas. The hotel offers a combination of quality dining and spacious meeting area in a relaxed atmosphere. Each of New Madinah Hotel&#39;s rooms is fitted with a private bathroom with bathtub and robes. Guests can relax with a refreshing beverage from the in-room minibar or watch satellite TV channels.</span></p>', 1, 38, NULL, '2025-03-12 16:54:58', '2025-03-12 16:54:58', 3),
(41, 'Ruve Al Madinah Hotel', 'Madinah', '<p style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px;\">\r\n	Genius discounts at this property are subject to book dates, stay dates and other available deals.&nbsp;<span style=\"font-family: var(--bui_font_body_2_font-family); font-size: var(--bui_font_body_2_font-size); font-weight: var(--bui_font_body_2_font-weight); white-space-collapse: preserve;\">Offering luxuriously decorated rooms with a balcony, the Ruve Al Madinah Hotel is strategically located 200 metres from Haram. The King Abdul Aziz historical library is a 10-minute walk away. Wooden furniture and warm orange tones feature in all rooms at the Rove Al Madinah . Each room offers a flat-screen TV, a work desk, and a minibar. Some also have a separate living room with a dining area.</span></p>\r\n<div data-capla-component-boundary=\"b-property-web-property-page/PropertyDescriptionDesktop\" data-capla-hydration=\"0\" style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px;\">\r\n	<div class=\"c82435a4b8\" style=\"box-sizing: border-box; padding: var(--bui_box_padding); --bui_box_padding: calc(var(--bui_box_spaced_padding--s) * var(--bui_spacing_1x)); --bui_box_spaced_padding--s: 0;\">\r\n		<div>\r\n			&nbsp;</div>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>', 1, 39, NULL, '2025-03-12 16:56:30', '2025-03-12 16:56:30', 3),
(42, 'Grand Zowar Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Ideally set in the Central Madinah district of Al Madinah, Grand Zowar Hotel is a 600m walk away from Al-Masjid an-Nabawi, 2.1 km from Old Bazaar and 2.6 km from Mazaya Mall. Among the facilities of this property are a restaurant, a 24-hour front desk and room service, along with free WiFi. Private parking can be arranged at an extra charge.</span></p>', 1, 40, NULL, '2025-03-12 16:58:46', '2025-03-12 16:58:46', 3),
(43, 'Odst Al Madinah Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Odst Al Madinah Hotel offers accommodation in Al Madinah. Guests can enjoy the on-site restaurant. Odst Al Madinah Hotel features free WiFi throughout the property. Each room is equipped with a flat-screen TV with satellite channels. Certain units include a seating area for your convenience. You will find a coffee machine in the room. Each room comes with a private bathroom fitted with a bath. Extras include slippers, free toiletries and a hairdryer. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 41, NULL, '2025-03-12 16:59:48', '2025-03-12 16:59:48', 3),
(44, 'Al Mokhtara Golden Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Al Mukhtara Golden is situated in the Central Madinah district, 500 metres from The Prophet&#39;s Mosque and 900 metres from Old Bazaar. Free WiFi in public areas. Some units include a seating area where you can relax. All rooms include a private bathroom equipped with a shower. You will find a 24-hour front desk, gift shop, and shops at the property.</span></p>', 1, 42, NULL, '2025-03-12 17:00:40', '2025-03-12 17:00:40', 3),
(45, 'Al Mukhtara International Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Mokhtara International in Al-Madinah al-Munawwarah offers comfortable rooms with air-conditioning, private bathrooms, and free WiFi throughout the property. Each room includes a hairdryer, free toiletries, shower, dressing room, carpeted floors, TV, and wardrobe. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Guests benefit from a 24-hour front desk, room service, and free on-site private parking. Additional amenities include a TV, wardrobe, and carpeted floors, ensuring a pleasant stay.</span></p>', 1, 43, NULL, '2025-03-12 17:02:07', '2025-03-12 17:02:07', 3),
(46, 'Karam Taibah Almasi', 'Madinah', '<p class=\"overview__text-item\" style=\"box-sizing: border-box; margin: 0px 0px 24px; padding: 0px; border: 0px; vertical-align: baseline; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 16px; line-height: 24px; font-family: Montserrat, sans-serif; color: rgb(97, 107, 120); background-color: rgb(242, 242, 242);\">\r\n	Karam Taibah Almasi Hotel Medina, located a 5-minute drive from Al-Baqi&#39;, features Wi-Fi in public areas. The hotel also provides guests with 24-hour security service and fire extinguishers.Some rooms are fitted with a private bathroom.</p>', 1, 44, NULL, '2025-03-12 17:03:35', '2025-03-12 17:03:35', 3),
(47, 'Al Mokhtara Diamond', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Al Mokhtara Diamond in Madinah Munawwara offers comfortable rooms with air-conditioning, private bathrooms, hairdryers, showers, and TVs. Free WiFi is available throughout the property.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> The hotel features a 24-hour front desk and room service. Additional amenities include a hairdryer, shower, and TV. Reception staff speak Arabic and English.</span></p>', 1, 45, NULL, '2025-03-12 17:06:11', '2025-03-12 17:06:11', 3),
(48, 'Zaha Al Madina Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Zaha Al Madina Hotel in Al Madinah offers family rooms with air-conditioning, private bathrooms, and city views. Each room includes a bidet, hairdryer, refrigerator, free toiletries, shower, TV, electric kettle, and wardrobe. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Guests enjoy free WiFi throughout the property, a lift, 24-hour front desk, housekeeping service, room service, and full-day security. The hotel provides a buffet halal breakfast and room service. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 46, NULL, '2025-03-12 17:07:20', '2025-03-12 17:07:20', 3),
(49, 'Jiwar Al Madina Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Jiwar Al Madina Hotel in Al Madinah offers family rooms with air-conditioning, private bathrooms, and city views. Each room includes a work desk, minibar, and free WiFi throughout the property.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The hotel features a family-friendly restaurant serving international cuisine with halal options. Guests can also enjoy a bar, coffee shop, and minimarket. Additional facilities include a lounge, lift, and 24-hour front desk.</span></p>', 1, 47, NULL, '2025-03-12 17:09:04', '2025-03-12 17:09:04', 3),
(50, 'Grand Plaza Madinah', 'Madinah', '<h3 class=\"e1eebb6a1e b484330d89\" style=\"margin: 0px; font-size: calc(var(--bui_spacing_4x) + var(--bui_spacing_half)); font-weight: var(--bui_font_strong_1_font-weight); line-height: var(--bui_font_strong_1_line-height); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; margin-block: 0px 0.67em; color: rgb(26, 26, 26);\">\r\n	About this property</h3>\r\n<p class=\"a53cbfa6de b3efd73f69\" data-testid=\"property-description\" style=\"font-size: 14px; line-height: var(--bui_font_body_2_line-height); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; white-space-collapse: preserve; color: rgb(26, 26, 26);\">\r\n	Grand Plaza Al Madina in Al Madinah offers a central position with Al-Masjid an-Nabawi an 8-minute walk away. Prince Mohammad bin Abdulaziz International Airport is 12 km from the hotel. Rooms feature air-conditioning, private bathrooms, minibars, and free WiFi. Additional amenities include hairdryers, refrigerators, and TVs.</p>', 1, 48, NULL, '2025-03-12 17:10:16', '2025-05-16 18:21:00', 3),
(51, 'Saja Al Madinah', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Saja Al Madinah is set in Al Madinah, 4 minute walking to The Prophet&#39;s Mosque. Each room at this hotel is air conditioned and is equipped with a flat-screen TV with satellite channels. Certain rooms feature a seating area to relax in after a busy day. Some units include views of the mountain or city. Every room has a private bathroom fitted with a shower. Extras include free toiletries and a hairdryer. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 49, NULL, '2025-03-12 17:12:27', '2025-03-12 17:12:27', 4),
(52, 'Golden Tulip Al Mektan', 'Madinah', '<h3 class=\"e1eebb6a1e b484330d89\" style=\"margin: 0px; font-size: calc(var(--bui_spacing_4x) + var(--bui_spacing_half)); font-weight: var(--bui_font_strong_1_font-weight); line-height: var(--bui_font_strong_1_line-height); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; margin-block: 0px 0.67em; color: rgb(26, 26, 26);\">\r\n	<span style=\"font-size: 14px; white-space-collapse: preserve;\">Rooms feature air-conditioning, private bathrooms, and modern amenities such as free WiFi, minibars, and flat-screen TVs. Guests enjoy city views, soundproofing, and private balconies. </span><span style=\"font-size: 14px; white-space-collapse: preserve;\">The family-friendly restaurant offers Middle Eastern and international cuisines in a modern setting. Breakfast includes continental, American, buffet, and vegan options with local specialities, fresh pastries, and more.</span></h3>', 1, 50, NULL, '2025-03-12 17:14:59', '2025-03-12 17:15:29', 4),
(53, 'Hayah Golden Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Situated in Medina, Al Hayah Golden Hotel is about a 5-minute walking distance from Prophet Muhammad&rsquo;s Mosque. Offers air-conditioned rooms and free Wi-Fi in public areas. Modern rooms come with a flat-screen TV at Al Hayah Golden Hotel. There is a 24-hour front desk. Prince Mohammad Bin Abdulaziz International Airport is 20 minutes&rsquo; drive from the hotel. Free private parking is possible on site and subject to availability. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 51, NULL, '2025-03-12 17:16:03', '2025-03-12 17:16:03', 4),
(54, 'Elaf Al Taqwa Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Elaf Al Taqwa Hotel in Madinah offers family rooms with air-conditioning, private bathrooms, and free WiFi. Each room includes a work desk, TV, and soundproofing for a pleasant stay. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The family-friendly restaurant serves halal meals with traditional and modern ambience. Guests can enjoy lunch and dinner in a welcoming environment.</span></p>', 1, 52, NULL, '2025-03-12 17:17:37', '2025-03-12 17:17:37', 4),
(55, 'Al Madina Harmony Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Modern comfort and traditional hospitality in the City of the Prophet. Crowne Plaza Madinah is located in the south area of Madinah Al Munawarah, just steps away from the Prophet Mohammed&rsquo;s Holy Mosque (PBUH) and BAB Al Salam. Being one of Madinah&rsquo;s 5-star hotels, it also provides an ideal location for pilgrims, leisure groups, business travelers, corporate meetings, airline crew, and passengers. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 53, NULL, '2025-03-12 17:20:10', '2025-03-12 17:20:10', 5),
(56, 'Anwar Al Madinah Movenpick Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">The 5-star Anwar Al Madinah M&ouml;venpick offers elegant accommodation less than 5 minutes&rsquo; walk from The Mosque of the Prophet Mohammad. It features 4 on-site restaurants. Free WiFi is available in all rooms. The elegant air-conditioned rooms at Anwar Al Madinah are spacious and modern. Each comes with a refrigerator, a work desk and satellite TV, as well as an en suite bathroom. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 54, NULL, '2025-03-12 17:21:01', '2025-03-12 17:21:01', 5),
(57, 'Hotel Pullman Zamzam Madinah', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Located in the holy city of Madinah Al Munawara and only 150 meters from Bab Al Salam of Al Masjid Al Nabawi, Pullman Zamzam Madina offers free WiFi throughout the entire hotel. All 835 rooms &amp; suites are blended with modern Arabic &amp; French elegance, All rooms are air-conditioned and feature free WiFi, a flat-screen TV and tea/coffee making facilities. Some rooms offer a seating area and sofa bed. The bathrooms are fitted with a shower.</span></p>', 1, 55, NULL, '2025-03-12 17:22:03', '2025-03-12 17:22:03', 5),
(58, 'Emaar Royal Hotel Medina', 'Madinah', '<p style=\"margin-block-start: 0px; color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px;\">\r\n	You might be eligible for a Genius discount at Emaar Royal Hotel. To check if a Genius discount is available for your selected dates&nbsp;<a class=\"bui-link\" href=\"https://account.booking.com/auth/oauth2?bkng_action=hotel&amp;aid=311984&amp;state=UpIIP1i21KL5LotFGANsYBIkiGjvZdTKOScqyndqCtzgDFj6UKxZiJVm-dGekjAF_O_4K6Lv7VdsZj6NmBFP2oUN2edxh_97AgYsXZsJFRd_tNP4dNBdGJQnRmbznjfCHkVyjYDLmAOuEEDcvoRszD2AtzblvS9rIbr8XsXlRgfwo-XRtEiU3_KzPCAtw6p78kCF6rm0-2hhGVLRou_SBsSCWODToz69uxWlHYWtf-aR7LE7wfIST8g3PF5NovQxFpjA6KAz9_OX4a0K-YNO9XoJf6rQi0bHLK5HpOHo2H_my4DEIR7uS3RaC7DK1vGPO97HFiC-NvHx-npSIpGqqiz3dyl-QBOW22tGtz5tA-SKtfgh3ylAQTqjYAmsuWYLpf4h62KAIEJwMiZXwcp8FGr1CJr15EXAHELTy1ga1giV-zOccdZ5fPAnCT0fcm0j-GJPhcCkabJcBqj2pXgEWu1WYQWLlqG-DXBSiafEroN77oJz2h0zVNdAHjU9nwxKApgOtSRFGasq7UndLbZR0ul2kM9g28chT9dIcMcx9hHBUcSvYh0xJAVJhyUaLdFaHO3_E0nfivcqNwudY1t9Fe1P_jPsuqLSwx74kPc_BiJu9bGq0bN5kjwl7uHhe8npJELNBLMjg5knA4yFXZULc6zHCje4VmkLb96Yqn9yJXCsiRyuIb3OxROeQT7PjdBhfj3eUe11kGHU3xHe-QeRhDlP30tsEyR9SeWDnr-icW_RXjQbZYRWjFGyxOh8x8V0USBm7xpMgjV29jP03_t6SZpA2liuasXsdnGo9jetCiFK4cgiNzvqErGN1-nE48jRRZT69nELmFaMpKjiZMp9vs6QrRwkDyRzk_IFQ4Si7MYWGUhEL7iBRVwNeAWg7X0jGksd1sFO4NxHvqhiUjPsosUQUyoNmmEDax-9Wuoz2KGypwWZ5yZDG6HGZmiKKNUUlU_6rC8QgxO6ePQMzcoaYf1EIUCfYfZt9AzjZQ9dPRPiWSvEiAeBmCgVpxfr760XKg-gKKjrP4gBl9DdSDyZlfRnQ8qkzpbtrpf9You_RWb5ftju7ZbVJauplWmsRWC6yiniasPNJoWO1Tzy4E3tn5BWYGOiLZ_QM0BADmRnyjmQmywcebrLcT0et-FzMwmoeU8zMd3i-6-6X9tetwdIJ7GHM16xi_lhkAbQJ_YsJISxUfCE1sEoz3OFp1NUR-h2zxVEwpeZMZozvJvfPD-IAXJlkyRHg1npCgxAol_IVHFIZDoVOf-AdKfrRJKVDdabLttUrsxQN2TZIlHK5P__fNochR3DwXVQnwPp60hHOcYwiUmwBj5NZQ3fRzMVk1sCNfJ8Lg462hz5qD7KtLRIXuh1PHJQkFmTB0DK3Th20exi6ErcHA&amp;lang=en-gb&amp;redirect_uri=https%3A%2F%2Fsecure.booking.com%2Flogin.html%3Fop%3Doauth_return&amp;dt=1741800152&amp;response_type=sso&amp;client_id=vO1Kblk7xX9tUn2cpZLS\" style=\"box-sizing: border-box; cursor: pointer; display: inline;\">sign in</a>.Genius discounts at this property are subject to book dates, stay dates and other available deals.<span style=\"font-family: var(--bui_font_body_2_font-family); font-size: var(--bui_font_body_2_font-size); font-weight: var(--bui_font_body_2_font-weight); white-space-collapse: preserve;\">located in the northern part of the central area , Emaar Royal Hotel is within 100 metres from the Prophet&rsquo;s Mosque. Some of its rooms have views of Mount Uhud or the mosque. All air-conditioned accommodation at Emaar Royal Hotel feature a modern d&eacute;cor with carpeted floors. Each room comes with a wardrobe, a minibar and a private bathroom.</span></p>\r\n<div data-capla-component-boundary=\"b-property-web-property-page/PropertyDescriptionDesktop\" data-capla-hydration=\"0\" style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px;\">\r\n	<div class=\"c82435a4b8\" style=\"box-sizing: border-box; padding: var(--bui_box_padding); --bui_box_padding: calc(var(--bui_box_spaced_padding--s) * var(--bui_spacing_1x)); --bui_box_spaced_padding--s: 0;\">\r\n		<div>\r\n			&nbsp;</div>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>', 1, 56, NULL, '2025-03-12 17:23:32', '2025-03-12 17:23:47', 5),
(59, 'Worth Peninsula', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Rooms feature private bathrooms, air-conditioning, city views, and modern amenities including free toiletries, tea and coffee makers, and flat-screen TVs. </span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> The hotel offers a restaurant serving continental, American, buffet, and &agrave; la carte breakfasts, as well as lunch and dinner.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests benefit from a lift, 24-hour front desk, concierge service, full-day security, and free on-site private parking.</span></p>', 1, 57, NULL, '2025-03-12 17:26:27', '2025-03-12 17:26:27', 5),
(60, 'Zowar International Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">This Zowar is located less than 180 meters from the Al-Masjid al-Nabawī in the central Northern area of Medina. It offers spacious, air-conditioned rooms with a private bathroom. There is a restaurant and a 24-hour front desk. All of the rooms at the Zowar International Hotel have a flat-screen TV, a minibar, and a safety deposit box. Each bathroom has a bath and free toiletries. Room service is also available on request. </span></p>\r\n<div>\r\n	&nbsp;</div>', 1, 58, NULL, '2025-03-12 17:27:53', '2025-03-12 17:27:53', 4);
