(62, 'Waqf Outhman Bin Affan Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Waqf Outhman Bin Affan Hotel in Al Madinah offers family rooms with air-conditioning, private bathrooms, and city views. Each room includes a work desk, TV, and free toiletries.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Guests can enjoy a restaurant serving halal African, British, Indonesian, and local cuisines. The hotel provides a continental buffet breakfast with fresh pastries, pancakes, cheese, and fruits.</span></p>', 1, 60, NULL, '2025-03-12 17:32:41', '2025-05-16 18:14:39', 4),
(63, 'Artal International Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Artal International Hotel in Al Madinah offers a central position with Al-Masjid an-Nabawi an 8-minute walk away. Prince Mohammad bin Abdulaziz International Airport is 12 km from the property.</span><span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\"> Rooms feature free WiFi, work desks, and showers. Family rooms and full-day security ensure a pleasant stay.</span></p>', 1, 61, NULL, '2025-03-12 17:34:51', '2025-03-12 17:34:51', 3),
(64, 'Dallah Taibah Hotel', 'Madinah', '<p>\r\n	<span style=\"color: rgb(26, 26, 26); font-family: BlinkMacSystemFont, -apple-system, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; white-space-collapse: preserve;\">Dallah Taibah Hotel is located 50 metres away from Al Masjid Al-Nabawi, immersed in the commercial and shopping district of Medina. Each spacious room at the Dallah Taibah has air conditioning and some of them feature views over the Masjid Al-Nabawi. All of them have flat-screen TVs and a safety deposit boxes. The bathrooms include free toiletries and slippers.</span></p>', 1, 62, NULL, '2025-03-12 17:36:20', '2025-03-12 17:36:20', 4),
