(1, 'ALHARAMAIN TRAVELS', 'Office 18, College Rd, Whalley Range, Manchester M16 8BP.', '0203 062 8926', NULL, 'info@alharamaintravel.co.uk', 'logo.jpg', 'footer-logo.jpg', 'favicon.jpg', '© Copyright 2025 Travigence as Al Haramain Travel - Company Number 15101982. All Rights Reserved.', '#', '#', NULL, '2024-06-03 18:21:22', '2025-05-29 08:18:55', NULL, '+44 208 164 3111', 'alharamaintravel.co.uk', NULL, '£', '500,1000,1500,2000,2500', '7,10,12,14', '3,4,5');
INSERT INTO `sliders` (`sliders_id`, `sliders_heading`, `sliders_subheading`, `sliders_textdetails`, `sliders_textdetails2`, `sliders_image`, `sliders_status`, `sliders_sort`, `created_at`, `updated_at`, `sliders_link`) VALUES
(1, 'The Divine Journey', 'HAQ TRAVELS', '<p>\r\n	We know Hajj and Umrah is your dream Pilgrimage.<br />\r\n	That&rsquo;s why we carefully select hotels and packages,<br />\r\n	sharing our experience to ensure your journey is stress-free.</p>', NULL, '', 1, 1, '2025-03-04 11:40:22', '2025-05-27 17:40:23', NULL);
INSERT INTO `staticpages` (`pages_id`, `pages_name`, `pages_details`, `pages_url`, `staticpages_image`, `pages_title`, `pages_descp`, `pages_keyword`, `pages_sort`, `pages_status`, `created_at`, `updated_at`, `pages_status_bottom`, `pages_bottom_incol`) VALUES
(1, 'All Umrah Packages', '<h1 dir=\"ltr\">\r\n	Cheap Umrah Packages from UK for 7 &amp; 14 Night Spiritual Journeys</h1>\r\n<p>\r\n	&nbsp;</p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Welcome to Haq Travels, a trusted provider of top-notch Umrah packages in the UK designed to offer you an exceptional and memorable spiritual experience.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Even if you are looking for affordable Umrah packages, exploring Umrah ticket prices, or planning ahead with our Umrah packages 2025, we are here to meet your Umrah needs.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">From budget Umrah packages to luxury Umrah packages, and everything in between, our goal is to make your pilgrimage smooth, sacred, and stress-free.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">With options including Umrah packages with flights, family Umrah packages, and women&#39;s Umrah packages in Leicester and all over the UK, you can find the perfect match tailored to your journey.</span></p>\r\n<p dir=\"ltr\">\r\n	&nbsp;</p>\r\n<h2 dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Discovering the Perfect Umrah Packages</span></h2>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">At Haq Travels, we understand the spiritual significance of performing Umrah, and we aim to make your pilgrimage seamless, memorable, and spiritually fulfilling.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Our wide range of Umrah packages in London is tailored to suit every individual&rsquo;s needs, regardless of whether you are a solo traveler, a couple, or traveling with family or in groups.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">From 3 star Umrah packages to 4 star Umrah packages, we offer carefully curated itineraries that include everything you need for a worry-free journey.</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">If you are looking for Umrah packages including flights, women&#39;s Umrah packages, or family Umrah packages, we ensure comfort, convenience, and a spiritually rewarding experience.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h2 dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Affordable Umrah Packages</span></h2>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Finding the right affordable Umrah packages in Manchester is easier than ever with Haq Travels. We have designed budget Umrah packages that allow pilgrims to fulfill their religious duties without financial stress.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Our cheap Umrah packages 2025 combine quality services with competitive pricing, ideal for those seeking value without compromise.</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Choose from 1 week Umrah packages, 10 days Umrah packages, or 14 days Umrah packages based on your availability and budget.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">We also offer seasonal pricing to help you find the cheapest Umrah packages during off-peak months.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h2 dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Exploring Umrah Ticket Prices</span></h2>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">We provide transparent Umrah ticket prices and guide you on the best time to travel, based on your preferences and budget.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Our partnerships with leading airlines enable us to offer a competitive Umrah package with a range of flight options.</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Even if you are looking to book early for August Umrah packages or planning a last-minute December Umrah package in Bradford, we ensure the best possible rates for all.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h2 dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Unparalleled Services and Amenities</span></h2>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Our all-in-one solutions are designed for comfort and peace of mind.&nbsp;</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">With Umrah packages all-inclusive, you can expect accommodation close to Haram, airport transfers, guided tours, and 24/7 support throughout your journey.</span></p>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">From luxury Umrah packages with VIP services to 4 star Umrah packages offering a blend of comfort and affordability, we leave no detail unattended.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h2 dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Tailored Umrah Packages for Every Season</span></h2>\r\n<p dir=\"ltr\">\r\n	<span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">Different seasons bring different opportunities for Umrah. At Haq Travels, we offer a variety of seasonal deals to match your calendar:</span></p>\r\n<p dir=\"ltr\">\r\n	<strong><span id=\"docs-internal-guid-e9a4a030-7fff-3ddf-c8c0-c80862a5de1d\">September Umrah packages:</span> </strong>Ideal for quieter travel before the b